package Java_Assignment;

public class Assignment_6_operator {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a=120;
		int b=243;
		int sum=a+b;
		System.out.println(sum);
		
		//'-' operator
		float a1=233.7f;
		double b1=344.9;
		double sub=b1-a1;
		System.out.println(sub);
		
		//'*' operator
		int a2=88;
		float b2=80.8f;
		float mul=a2*b2;
		System.out.println(mul);
		
		//'/' operator
		double a3=44.6789;
		int b3=2002;
		double div=a3/b3;
		System.out.println(div);
		
		//'%' operator
		int a4=595;
		double b4=7.1;
		double per=a4%b4;
		System.out.println(per);
	}

}
